import React from "react";
import { motion } from "framer-motion";

const experiences = [
  { title: "Supply Chain & Operations Project Manager", company: "Samsung", date: "2024 – Présent" },
  { title: "Chef de projet MOA", company: "Oplit", date: "2023 - 2024" },
  { title: "COO Adjoint", company: "Arvato BU Healthcare", date: "2022 - 2023" }
];

const ExperienceCard = () => {
  return (
    <div className="experience-container">
      {experiences.map((exp, index) => (
        <motion.div key={index} className="experience-card"
          initial={{ opacity: 0, y: 50 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: index * 0.2 }}
        >
          <h2>{exp.title}</h2>
          <h3>{exp.company}</h3>
          <p>{exp.date}</p>
        </motion.div>
      ))}
    </div>
  );
};

export default ExperienceCard;
